function Dashboard() {
  const [stats, setStats] = useState({
    totalProducts: 0,
    totalInventory: 0,
    lowStock: 0,
    capacity: []
  });
  const [loading, setLoading] = useState(true);
  const [setupMessage, setSetupMessage] = useState('');
  const [setupLoading, setSetupLoading] = useState(false);

  // Gá»i nhiá»u API cÃ¹ng lÃºc Ä‘á»ƒ láº¥y sá»‘ liá»‡u thá»‘ng kÃª
  const fetchDashboardData = async () => {
    setLoading(true);
    try {
      const token = localStorage.getItem('token');
      const headers = { 'Authorization': `Bearer ${token}` };

      const [prodRes, invRes, overviewRes] = await Promise.all([
        fetch(`${API_BASE}/products`, { headers }).then(res => res.json()),
        fetch(`${API_BASE}/inventory`, { headers }).then(res => res.json()),
        fetch(`${API_BASE}/inbound/warehouse-overview`, { headers }).then(res => res.json())
      ]);

      let totalInv = 0;
      let lowStockCount = 0;

      if (invRes.success) {
        totalInv = invRes.data.reduce((sum, item) => sum + Number(item.So_Luong_Ton), 0);
      }

      if (prodRes.success) {
        lowStockCount = prodRes.products.filter(p => Number(p.inventory) <= 5).length;
      }

      // Xá»­ lÃ½ dá»¯ liá»‡u sá»©c chá»©a kho (MÃ´ phá»ng sá»©c chá»©a tá»‘i Ä‘a má»—i khu lÃ  500 Bin)
      const MAX_BIN_PER_ZONE = 500; 
      let capacityData = [];
      if (overviewRes.success && overviewRes.data) {
        Object.values(overviewRes.data).forEach(cat => {
          Object.values(cat.zones).forEach(zone => {
            const used = MAX_BIN_PER_ZONE - zone.emptyCount;
            const percent = Math.round((used / MAX_BIN_PER_ZONE) * 100);
            capacityData.push({
              name: zone.zoneName,
              code: zone.zoneCode,
              used: used,
              total: MAX_BIN_PER_ZONE,
              percent: percent > 0 ? percent : 0
            });
          });
        });
      }

      setStats({
        totalProducts: prodRes.success ? prodRes.products.length : 0,
        totalInventory: totalInv,
        lowStock: lowStockCount,
        capacity: capacityData.slice(0, 4) // Láº¥y 4 khu vá»±c tiÃªu biá»ƒu Ä‘á»ƒ váº½ biá»ƒu Ä‘á»“
      });

    } catch (error) {
      console.error('Lá»—i táº£i dá»¯ liá»‡u dashboard:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchDashboardData();
  }, []);

  // Giá»¯ láº¡i nÃºt Setup kho phÃ²ng há» giÃ¡o viÃªn báº¯t cháº¡y thá»­ tá»« Ä‘áº§u
  const generateBins = async () => {
    setSetupLoading(true);
    setSetupMessage('â³ Äang nhá» thá»£ xÃ¢y dá»±ng 3000 vá»‹ trÃ­ ká»‡ kho...');
    try {
      const response = await fetch(`${API_BASE}/locations/generate`, { method: 'POST' });
      const data = await response.json();
      setSetupMessage(data.success ? `âœ… ${data.message}` : `âŒ Lá»—i: ${data.message}`);
    } catch (error) {
      setSetupMessage('âŒ Lá»—i káº¿t ná»‘i Ä‘áº¿n mÃ¡y chá»§!');
    } finally {
      setSetupLoading(false);
    }
  };

  return (



