const API_BASE = window.location.hostname === 'localhost' 
  ? 'http://localhost:5000/api'               // Náº¿u cháº¡y á»Ÿ mÃ¡y nhÃ  -> Gá»i Localhost
  : 'https://doan-qlk.onrender.com/api';      // Náº¿u cháº¡y trÃªn Vercel -> Gá»i Render

// Mapping Zone Code -> TÃªn hiá»ƒn thá»‹
const zoneConfig = {
  'TV-SN': 'Tivi Sony',
  'TV-SS': 'Tivi Samsung',
