function Inbound() {
  // ============================================
  // STATE QUáº¢N LÃ
  // ============================================
  const [activeTab, setActiveTab] = useState('create'); // 'create' | 'list'
  const [receipts, setReceipts] = useState([]);
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(false);
  const [warehouseOverview, setWarehouseOverview] = useState(null);

  // State cho form táº¡o phiáº¿u
  const [items, setItems] = useState([]);
  const [suggestedBins, setSuggestedBins] = useState(null);
  const [submitResult, setSubmitResult] = useState(null);

  // State cho modal chi tiáº¿t
  const [selectedReceipt, setSelectedReceipt] = useState(null);
  const [showDetailModal, setShowDetailModal] = useState(false);

  // Pagination
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [totalReceipts, setTotalReceipts] = useState(0);

  // ============================================
  // AUTHORIZATION
  // ============================================
  const userString = localStorage.getItem('user');
  const currentUser = (userString && userString !== "undefined") ? JSON.parse(userString) : null;
  const userRole = currentUser?.role || '';
  const canCreate = userRole === 'ADMIN' || userRole === 'KHO';
  const canApprove = userRole === 'ADMIN' || userRole === 'KHO';

  // ============================================
  // HELPER: Gá»ŒI API
  // ============================================
  const getAuthHeaders = () => {
    const token = localStorage.getItem('token');
    return { 
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${token}`
    };
  };

  const apiCall = async (url, options = {}) => {
    const response = await fetch(`${API_BASE}${url}`, {
      ...options,
      headers: { ...getAuthHeaders(), ...options.headers }
    });
    return response.json();
  };

  // ============================================
  // LOAD DATA KHI MOUNT
  // ============================================
  useEffect(() => {
    fetchProducts();
    fetchWarehouseOverview();
    if (activeTab === 'list') {
      fetchReceipts();
    }
  }, [activeTab, page]);

  // ============================================
  // FETCH FUNCTIONS
  // ============================================
  const fetchProducts = async () => {
    try {
      const data = await apiCall('/products');
      if (data.success) setProducts(data.products);
    } catch (error) {
      console.error('Error fetching products:', error);
    }
  };

  const fetchWarehouseOverview = async () => {
    try {
      const data = await apiCall('/inbound/warehouse-overview');
      if (data.success) setWarehouseOverview(data.data);
    } catch (error) {
      console.error('Error fetching warehouse overview:', error);
    }
  };

  const fetchReceipts = async () => {
    setLoading(true);
    try {
      const data = await apiCall(`/inbound?page=${page}&limit=10`);
      if (data.success) {
        setReceipts(data.data);
        setTotalPages(data.pagination.totalPages);
        setTotalReceipts(data.pagination.total);
      }
    } catch (error) {
      console.error('Error fetching receipts:', error);
    } finally {
      setLoading(false);
    }
  };

  const fetchReceiptDetails = async (receiptId) => {
    setLoading(true);
    try {
      const data = await apiCall(`/inbound/${receiptId}`);
      if (data.success) {
        setSelectedReceipt(data.data);
        setShowDetailModal(true);
      }
    } catch (error) {
      alert('Lá»—i khi táº£i chi tiáº¿t phiáº¿u!');
    } finally {
      setLoading(false);
    }
  };

  // ============================================
  // Xá»¬ LÃ THÃŠM/Sá»¬A/XÃ“A Sáº¢N PHáº¨M TRONG PHIáº¾U
  // ============================================
  const handleAddItem = () => {
    setItems([...items, { productId: '', quantity: 1, suggestedBin: null }]);
  };

  const handleRemoveItem = (index) => {
    const newItems = items.filter((_, i) => i !== index);
    setItems(newItems);
    setSuggestedBins(null);
  };

  const handleItemChange = (index, field, value) => {
    const newItems = [...items];
    newItems[index] = { ...newItems[index], [field]: value };
    setItems(newItems);

    // Reset suggested bins khi Ä‘á»•i sáº£n pháº©m
    if (field === 'productId') {
      setSuggestedBins(null);
    }
  };

  // ============================================
  // Gá»¢I Ã Vá»Š TRÃ BIN
  // ============================================
  const handleSuggestBins = async (itemIndex) => {
    const item = items[itemIndex];
    if (!item.productId || !item.quantity) {
      alert('Vui lÃ²ng chá»n sáº£n pháº©m vÃ  nháº­p sá»‘ lÆ°á»£ng!');
      return;
    }

    try {
      const data = await apiCall('/inbound/suggest-bins', {
        method: 'POST',
        body: JSON.stringify({ product_id: parseInt(item.productId), quantity: parseInt(item.quantity) })
      });

      if (data.success) {
        setSuggestedBins(data.data);
      } else {
        alert(data.message || 'KhÃ´ng tÃ¬m tháº¥y vá»‹ trÃ­ phÃ¹ há»£p!');
      }
    } catch (error) {
      alert('Lá»—i khi gá»£i Ã½ vá»‹ trÃ­!');
    }
  };

  // ============================================
  // SUBMIT PHIáº¾U NHáº¬P KHO
  // ============================================
  const handleSubmit = async (e) => {
    e.preventDefault();

    if (items.length === 0) {
      alert('Vui lÃ²ng thÃªm Ã­t nháº¥t 1 sáº£n pháº©m!');
      return;
    }

    // Validate
    for (let item of items) {
      if (!item.productId) {
        alert('Vui lÃ²ng chá»n sáº£n pháº©m cho táº¥t cáº£ cÃ¡c dÃ²ng!');
        return;
      }
      if (!item.quantity || item.quantity <= 0) {
        alert('Sá»‘ lÆ°á»£ng pháº£i lá»›n hÆ¡n 0!');
        return;
      }
    }

    setLoading(true);
    try {
      const data = await apiCall('/inbound', {
        method: 'POST',
        body: JSON.stringify({
          items: items.map(item => ({
            productId: parseInt(item.productId),
            quantity: parseInt(item.quantity)
          }))
        })
      });

      if (data.success) {
        setSubmitResult(data.data);
        // Reset form
        setItems([]);
        setSuggestedBins(null);
        // Refresh data
        fetchWarehouseOverview();
        fetchReceipts();
        // Chuyá»ƒn sang tab danh sÃ¡ch sau 2 giÃ¢y
        setTimeout(() => {
          setActiveTab('list');
          setSubmitResult(null);
        }, 2000);
      } else {
        alert(data.message || 'Lá»—i khi táº¡o phiáº¿u nháº­p!');
      }
    } catch (error) {
      alert('Lá»—i káº¿t ná»‘i mÃ¡y chá»§!');
    } finally {
      setLoading(false);
    }
  };

  // ============================================
  // DUYá»†T PHIáº¾U NHáº¬P
  // ============================================
  const handleApprove = async (receiptId, action) => {
    if (!confirm(`XÃ¡c nháº­n ${action === 'approve' ? 'duyá»‡t' : 'tá»« chá»‘i'} phiáº¿u nháº­p nÃ y?`)) return;

    setLoading(true);
    try {
      const data = await apiCall(`/inbound/${receiptId}/approve`, {
        method: 'PUT',
        body: JSON.stringify({ action })
      });

      if (data.success) {
        alert(data.message);
        fetchReceipts();
        setShowDetailModal(false);
      } else {
        alert(data.message);
      }
    } catch (error) {
      alert('Lá»—i khi duyá»‡t phiáº¿u!');
    } finally {
      setLoading(false);
    }
  };

  // ============================================
  // RENDER: TAB Táº O PHIáº¾U NHáº¬P
  // ============================================
  const renderCreateTab = () => (


      {/* Form nháº­p kho */}






             Táº¡o Phiáº¿u Nháº­p Kho Má»›i


