import { useState } from 'react';
import { useNavigate } from 'react-router-dom';

// Há»‡ thá»‘ng tá»± Ä‘á»™ng quÃ©t xem trang web Ä‘ang cháº¡y á»Ÿ Ä‘Ã¢u Ä‘á»ƒ gá»i Ä‘Ãºng API
const API_BASE = window.location.hostname === 'localhost' 
  ? 'http://localhost:5000/api'
  : 'https://doan-qlk.onrender.com/api';

function Login() {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [message, setMessage] = useState('');

  const navigate = useNavigate();

  const handleLogin = async (e) => {
    e.preventDefault();
    try {
      // ÄÃ£ thay link cá»©ng báº±ng API_BASE tá»± Ä‘á»™ng
      const response = await fetch(`${API_BASE}/auth/login`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ username, password })
      });

      const data = await response.json();

      if (data.success) {
        // 1. LÆ°u "tháº» ra vÃ o" (token) vÃ  thÃ´ng tin user vÃ o bá»™ nhá»› trÃ¬nh duyá»‡t
        localStorage.setItem('token', data.token);
        localStorage.setItem('user', JSON.stringify(data.user));

        // 2. Chuyá»ƒn hÆ°á»›ng tháº³ng vÃ o trang Tá»•ng quan
        navigate('/');
      } else {
        setMessage(`âŒ ${data.message}`);
      }
    } catch (error) {
      setMessage('âŒ Lá»—i khÃ´ng káº¿t ná»‘i Ä‘Æ°á»£c Backend!');
    }
  };

  return (



Há»‡ Thá»‘ng Quáº£n LÃ½ Kho



          TÃ i khoáº£n:

           setUsername(e.target.value)}
            style={{ width: '250px', padding: '8px', marginTop: '5px' }}
          />



          Máº­t kháº©u:

           setPassword(e.target.value)}
            style={{ width: '250px', padding: '8px', marginTop: '5px' }}
          />


          ÄÄƒng Nháº­p



{message}

  );
}

