function Outbound() {
  const [activeTab, setActiveTab] = useState('create');
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(false);
  const [items, setItems] = useState([]);
  const [submitResult, setSubmitResult] = useState(null);

  const userString = localStorage.getItem('user');
  const currentUser = (userString && userString !== "undefined") ? JSON.parse(userString) : null;
  const userRole = currentUser?.role || '';
  const canCreate = userRole === 'ADMIN' || userRole === 'KHO' || userRole === 'SALES';

  const getAuthHeaders = () => {
    const token = localStorage.getItem('token');
    return { 
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${token}`
    };
  };

  useEffect(() => {
    fetchProducts();
  }, []);

  const fetchProducts = async () => {
    try {
      const response = await fetch(`${API_BASE}/products`, { headers: getAuthHeaders() });
      const data = await response.json();
      // Chá»‰ láº¥y nhá»¯ng sáº£n pháº©m Ä‘ang cÃ³ tá»“n kho > 0 Ä‘á»ƒ hiá»ƒn thá»‹ cho xuáº¥t
      if (data.success) {
        setProducts(data.products.filter(p => p.inventory > 0));
      }
    } catch (error) {
      console.error('Lá»—i táº£i sáº£n pháº©m:', error);
    }
  };

  const handleAddItem = () => {
    setItems([...items, { productId: '', quantity: 1 }]);
  };

  const handleRemoveItem = (index) => {
    setItems(items.filter((_, i) => i !== index));
  };

  const handleItemChange = (index, field, value) => {
    const newItems = [...items];
    newItems[index] = { ...newItems[index], [field]: value };
    setItems(newItems);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (items.length === 0) return alert('Vui lÃ²ng thÃªm Ã­t nháº¥t 1 sáº£n pháº©m cáº§n xuáº¥t!');

    // Kiá»ƒm tra tÃ­nh há»£p lá»‡
    for (let item of items) {
      if (!item.productId) return alert('Vui lÃ²ng chá»n sáº£n pháº©m!');
      if (!item.quantity || item.quantity <= 0) return alert('Sá»‘ lÆ°á»£ng xuáº¥t pháº£i lá»›n hÆ¡n 0!');

      const productObj = products.find(p => p.id === parseInt(item.productId));
      if (productObj && item.quantity > productObj.inventory) {
        return alert(`Sáº£n pháº©m ${productObj.name} chá»‰ cÃ²n ${productObj.inventory} cÃ¡i trong kho, khÃ´ng Ä‘á»§ Ä‘á»ƒ xuáº¥t ${item.quantity}!`);
      }
    }

    setLoading(true);
    try {
      const response = await fetch(`${API_BASE}/outbound`, {
        method: 'POST',
        headers: getAuthHeaders(),
        body: JSON.stringify({
          user_id: currentUser?.id,
          items: items.map(item => ({
            productId: parseInt(item.productId),
            quantity: parseInt(item.quantity)
          }))
        })
      });

      const data = await response.json();

      if (data.success) {
        setSubmitResult(data.data);
        setItems([]);
        fetchProducts(); // Táº£i láº¡i Ä‘á»ƒ update sá»‘ tá»“n kho má»›i
        setTimeout(() => setSubmitResult(null), 5000);
      } else {
        alert('Lá»—i: ' + data.message);
      }
    } catch (error) {
      alert('Lá»—i káº¿t ná»‘i Ä‘áº¿n mÃ¡y chá»§!');
    } finally {
      setLoading(false);
    }
  };

  return (







Xuáº¥t Kho (Outbound)

QuÃ©t vÃ  xuáº¥t hÃ ng ra khá»i ká»‡ Bin



      {submitResult && (






ÄÃ£ xuáº¥t kho thÃ nh cÃ´ng!

MÃ£ phiáº¿u xuáº¥t: {submitResult.receiptCode}


      )}





           Láº­p Phiáº¿u Xuáº¥t Kho






            Sáº£n pháº©m cáº§n xuáº¥t

